"use client";

import { useState } from "react";
import {
  verifyCertificate,
  certificateId,
  type VerifiedCertificate,
} from "@/lib/marketing-tests/exams";
import type { ExamResult } from "@/components/marketing/ExamCertificate";
import { Card, Button, Badge, Input } from "@/components/marketing/ui";

function fmtDate(epochMs: number): string {
  return new Date(epochMs).toLocaleDateString(undefined, {
    year: "numeric",
    month: "long",
    day: "numeric",
  });
}

export function CertificateVerify({
  history,
  onBack,
}: {
  history: ExamResult[];
  onBack: () => void;
}) {
  const [input, setInput] = useState("");
  const [result, setResult] = useState<VerifiedCertificate | null>(null);

  const mapped = history.map((a) => ({
    examId: a.examId,
    examTitle: a.examTitle,
    candidate: a.candidate,
    percentage: a.percentage,
    passed: a.passed,
    takenAt: a.takenAt,
    band: a.band.band,
  }));

  function runVerify(certId: string) {
    setInput(certId);
    setResult(verifyCertificate(certId, mapped));
  }

  const recentPassing = history
    .filter((a) => a.passed)
    .slice(-5)
    .reverse();

  return (
    <div className="mx-auto max-w-2xl space-y-6">
      <div className="flex items-center gap-3">
        <Button variant="outline" onClick={onBack}>
          ← Back
        </Button>
        <h2 className="text-2xl font-bold">Certificate Verification</h2>
      </div>

      <Card className="space-y-4 p-6">
        <div className="flex gap-2">
          <Input
            value={input}
            onChange={(e) => setInput(e.target.value)}
            placeholder="MKT-XXXXXXXX"
            className="font-mono"
          />
          <Button onClick={() => runVerify(input)}>Verify</Button>
        </div>

        {result === null && (
          <p className="text-sm text-muted-foreground">
            Enter a certificate ID to verify.
          </p>
        )}

        {result !== null && result.valid && (
          <Card className="border-green-500 space-y-3 p-6">
            <Badge variant="default" className="bg-green-600">
              Certificate Verified ✓
            </Badge>
            <div className="space-y-1">
              <p className="text-lg font-semibold">
                {result.candidate ?? "Unknown candidate"}
              </p>
              <p className="text-sm">{result.examTitle ?? "Unknown exam"}</p>
              <p className="text-sm">
                Score: {result.percentage != null ? `${result.percentage}%` : "—"}
                {result.band ? ` · Band: ${result.band}` : ""}
              </p>
              {result.takenAt != null && (
                <p className="text-sm">Issued: {fmtDate(result.takenAt)}</p>
              )}
            </div>
            <div className="rounded border bg-muted p-2 font-mono text-sm">
              {result.certificateId}
            </div>
          </Card>
        )}

        {result !== null && !result.valid && (
          <Card className="border-red-500 p-6">
            <p className="text-sm text-red-600">
              Certificate not found — check the ID and try again.
            </p>
          </Card>
        )}
      </Card>

      {recentPassing.length > 0 && (
        <div className="space-y-2">
          <p className="text-sm font-medium">Recent valid certificates</p>
          <div className="flex flex-wrap gap-2">
            {recentPassing.map((a, i) => {
              const cid = certificateId(a.examId, a.candidate, a.takenAt);
              return (
                <button
                  key={`${a.examId}-${a.takenAt}-${i}`}
                  onClick={() => runVerify(cid)}
                  className="rounded-full border bg-muted px-3 py-1 font-mono text-xs hover:bg-muted/70"
                >
                  {cid}
                </button>
              );
            })}
          </div>
        </div>
      )}
    </div>
  );
}
EOF
